INSERT INTO reviews (reviewer_name, reviewer_email, rating, comment, guide_user_id, hidden, created_at) VALUES
('Sarah Mitchell', 'sarah.m@email.com', 5, 'Michael was an incredible guide! His knowledge of DC history made the tour unforgettable. Every stop had a fascinating story behind it.', '26477b85-de16-4946-935a-f6e238a0fd8d', false, '2025-10-05T14:00:00Z'),
('James & Linda Park', 'jpark@email.com', 5, 'We booked a private tour of NYC and it exceeded all expectations. Michael knew every hidden gem and the best spots for photos!', '26477b85-de16-4946-935a-f6e238a0fd8d', false, '2025-10-22T10:30:00Z'),
('Roberto Gonzalez', 'rgonzalez@email.com', 4, 'Great Niagara Falls tour. Very well organized and Michael was super accommodating with our schedule changes. Highly recommend!', '26477b85-de16-4946-935a-f6e238a0fd8d', false, '2025-11-08T16:00:00Z'),
('Emily Watson', 'ewatson@email.com', 5, 'Absolutely loved the Washington DC monuments tour at sunset. Michael''s passion for history really shines through. A must-do experience!', '26477b85-de16-4946-935a-f6e238a0fd8d', false, '2025-11-19T09:15:00Z'),
('Takeshi Yamamoto', 'tyamamoto@email.com', 5, 'As a tourist from Japan, I appreciated how patient and clear Michael was. The tour of the Capitol and Smithsonian was perfectly paced.', '26477b85-de16-4946-935a-f6e238a0fd8d', false, '2025-12-03T11:00:00Z'),
('Marie Dubois', 'marie.d@email.com', 4, 'Wonderful Toronto city tour! Michael showed us neighborhoods we never would have found on our own. Only wish we had more time!', '26477b85-de16-4946-935a-f6e238a0fd8d', false, '2025-12-18T13:45:00Z'),
('David & Karen Thompson', 'dthompson@email.com', 5, 'Our family of 6 had the best day exploring NYC with Michael. He kept the kids engaged and found amazing restaurants for lunch. 10/10!', '26477b85-de16-4946-935a-f6e238a0fd8d', false, '2026-01-07T10:00:00Z'),
('Anna Kowalski', 'akowalski@email.com', 5, 'Michael''s DC tour was the highlight of our trip from Poland. His storytelling made every monument come alive. We felt like VIPs!', '26477b85-de16-4946-935a-f6e238a0fd8d', false, '2026-01-20T15:30:00Z'),
('Marcus Johnson', 'mjohnson@email.com', 4, 'Booked a last-minute Niagara Falls tour and Michael made it happen seamlessly. Professional, knowledgeable, and genuinely fun to be around.', '26477b85-de16-4946-935a-f6e238a0fd8d', false, '2026-02-01T12:00:00Z'),
('Sophie Chen', 'schen@email.com', 5, 'Third time booking with iGuide Tours and Michael never disappoints. This time we did the full NYC experience — Brooklyn Bridge, Central Park, and more. Perfection!', '26477b85-de16-4946-935a-f6e238a0fd8d', false, '2026-02-08T09:00:00Z');